//! Q5_0 mat-vec via bit-plane dilation + LUT — the technique at 5-bit.
//!
//! Q5_0 is symmetric: `w = d·(q − 16)`, q ∈ 0..31 (4-bit nibble + a 5th bit packed
//! in the per-block `qh` u32), one `d` per 32-element block. So
//! `Σ w·x = Σ_block d·(Σ q·x − 16·Σ x)`. The 5th-bit spread (awkward at runtime in
//! NEON) is done ONCE in the offline repack; the hot loop lifts q into 5 bit-planes
//! and resolves 16 rows per `vqtbl1q`. Fills the Q5_0 NEON gap (scalar on ARM today).

use crate::math::f16_to_f32;

const GROUP: usize = 4;
const REGION: usize = 32; // one Q5_0 scale per 32-element block
const GROUPS_PER_REGION: usize = REGION / GROUP; // 8
const PLANES: usize = 5; // 5-bit quant

/// Decode a Q5_0 row into (qval[c] ∈ 0..31, A[block] = d); mirrors `dequantize_q5_0_row`.
fn decode_q5_0_row(w: &[u8], r: usize, d: usize, qval: &mut [u8], a: &mut [f32]) {
    let bpr = d / REGION;
    let row = &w[r * bpr * 22..(r + 1) * bpr * 22];
    for b in 0..bpr {
        let bp = &row[b * 22..(b + 1) * 22];
        let d_val = f16_to_f32(u16::from_le_bytes([bp[0], bp[1]]));
        let qh = u32::from_le_bytes([bp[2], bp[3], bp[4], bp[5]]);
        let qs = &bp[6..22];
        a[b] = d_val;
        for j in 0..16 {
            let lo = (qs[j] & 0x0f) | ((((qh >> j) & 1) as u8) << 4);
            let hi = (qs[j] >> 4) | ((((qh >> (j + 16)) & 1) as u8) << 4);
            qval[b * 32 + j] = lo;
            qval[b * 32 + j + 16] = hi;
        }
    }
}

pub struct Q50Bitplanes {
    pub n: usize,
    pub d: usize,
    regions: usize,
    a: Vec<f32>,
    masks: Vec<u8>,
}

pub fn q5_0_to_bitplanes(w: &[u8], n: usize, d: usize) -> Q50Bitplanes {
    let regions = d / REGION;
    let mut a = vec![0.0f32; n * regions];
    let mut masks = vec![0u8; n * regions * PLANES * GROUPS_PER_REGION];
    let mut qval = vec![0u8; d];
    let mut arow = vec![0.0f32; regions];
    for r in 0..n {
        decode_q5_0_row(w, r, d, &mut qval, &mut arow);
        for reg in 0..regions {
            a[r * regions + reg] = arow[reg];
            for g in 0..GROUPS_PER_REGION {
                for plane in 0..PLANES {
                    let mut m = 0u8;
                    for i in 0..GROUP {
                        let q = qval[reg * REGION + g * GROUP + i];
                        m |= ((q >> plane) & 1) << i;
                    }
                    let idx = ((r * regions + reg) * PLANES + plane) * GROUPS_PER_REGION + g;
                    masks[idx] = m;
                }
            }
        }
    }
    Q50Bitplanes { n, d, regions, a, masks }
}

/// Scalar float-LUT reference (exact; validates format + decomposition).
pub fn mat_vec_q5_0_lut_scalar(out: &mut [f32], x: &[f32], bp: &Q50Bitplanes) {
    let regs = bp.regions;
    let mut lut = vec![0.0f32; regs * GROUPS_PER_REGION * 16];
    let mut sx = vec![0.0f32; regs];
    for reg in 0..regs {
        let mut tot = 0.0f32;
        for g in 0..GROUPS_PER_REGION {
            let base = &x[reg * REGION + g * GROUP..reg * REGION + g * GROUP + GROUP];
            let o = &mut lut[(reg * GROUPS_PER_REGION + g) * 16..(reg * GROUPS_PER_REGION + g) * 16 + 16];
            o[0] = 0.0;
            for mm in 1..16usize {
                let low = mm.trailing_zeros() as usize;
                o[mm] = o[mm & (mm - 1)] + base[low];
            }
            tot += base.iter().sum::<f32>();
        }
        sx[reg] = tot;
    }
    for r in 0..bp.n {
        let mut acc = 0.0f32;
        for reg in 0..regs {
            let mut qdot = 0.0f32;
            for plane in 0..PLANES {
                let mut sp = 0.0f32;
                for g in 0..GROUPS_PER_REGION {
                    let idx = ((r * regs + reg) * PLANES + plane) * GROUPS_PER_REGION + g;
                    sp += lut[(reg * GROUPS_PER_REGION + g) * 16 + bp.masks[idx] as usize];
                }
                qdot += ((1u32 << plane) as f32) * sp;
            }
            acc += bp.a[r * regs + reg] * (qdot - 16.0 * sx[reg]);
        }
        out[r] = acc;
    }
}

/// NEON-blocked repack (16 rows/`vqtbl`). `B = −16·A`. Requires n % 16 == 0.
#[cfg(target_arch = "aarch64")]
pub struct Q50BitplanesNeon {
    pub n: usize,
    pub d: usize,
    regions: usize,
    a: Vec<f32>,
    b: Vec<f32>,
    masks: Vec<u8>,
}

#[cfg(target_arch = "aarch64")]
pub fn q5_0_to_bitplanes_neon(w: &[u8], n: usize, d: usize) -> Q50BitplanesNeon {
    assert!(n.is_multiple_of(16), "NEON path requires n % 16 == 0");
    let regions = d / REGION;
    let blocks16 = n / 16;
    let mut a = vec![0.0f32; blocks16 * regions * 16];
    let mut b = vec![0.0f32; blocks16 * regions * 16];
    let mut masks = vec![0u8; blocks16 * regions * PLANES * GROUPS_PER_REGION * 16];
    let mut qval = vec![0u8; d];
    let mut arow = vec![0.0f32; regions];
    for r in 0..n {
        let blk = r / 16;
        let rib = r % 16;
        decode_q5_0_row(w, r, d, &mut qval, &mut arow);
        for reg in 0..regions {
            a[(blk * regions + reg) * 16 + rib] = arow[reg];
            b[(blk * regions + reg) * 16 + rib] = -16.0 * arow[reg];
            for g in 0..GROUPS_PER_REGION {
                for plane in 0..PLANES {
                    let mut m = 0u8;
                    for i in 0..GROUP {
                        let q = qval[reg * REGION + g * GROUP + i];
                        m |= ((q >> plane) & 1) << i;
                    }
                    let idx = (((blk * regions + reg) * PLANES + plane) * GROUPS_PER_REGION + g) * 16 + rib;
                    masks[idx] = m;
                }
            }
        }
    }
    Q50BitplanesNeon { n, d, regions, a, b, masks }
}

#[cfg(target_arch = "aarch64")]
pub fn mat_vec_q5_0_lut_neon(out: &mut [f32], x: &[f32], bp: &Q50BitplanesNeon) {
    use gnosis_frf::prelude::*;
    let regs = bp.regions;
    let mut lut = vec![0i8; regs * GROUPS_PER_REGION * 16];
    let mut sxq = vec![0.0f32; regs];
    let mut sx = vec![0.0f32; regs];
    for reg in 0..regs {
        let seg = &x[reg * REGION..reg * REGION + REGION];
        let mx = seg.iter().fold(0.0f32, |a, &v| a.max(v.abs()));
        let scale = if mx > 0.0 { mx / 31.0 } else { 1.0 };
        sxq[reg] = scale;
        sx[reg] = seg.iter().sum();
        for g in 0..GROUPS_PER_REGION {
            let base = &seg[g * GROUP..g * GROUP + GROUP];
            let o = &mut lut[(reg * GROUPS_PER_REGION + g) * 16..(reg * GROUPS_PER_REGION + g) * 16 + 16];
            for mm in 0..16usize {
                let mut acc = 0i32;
                for i in 0..GROUP {
                    if (mm >> i) & 1 == 1 {
                        acc += (base[i] / scale).round().clamp(-31.0, 31.0) as i32;
                    }
                }
                o[mm] = acc as i8;
            }
        }
    }
    out.par_chunks_mut(16).enumerate().for_each(|(blk, chunk)| unsafe {
        use std::arch::aarch64::*;
        let mut yacc = [vdupq_n_f32(0.0); 4];
        for reg in 0..regs {
            let mut p = [[vdupq_n_s32(0); 4]; PLANES];
            for plane in 0..PLANES {
                for g in 0..GROUPS_PER_REGION {
                    let tbl = vld1q_s8(lut.as_ptr().add((reg * GROUPS_PER_REGION + g) * 16));
                    let mbase = (((blk * regs + reg) * PLANES + plane) * GROUPS_PER_REGION + g) * 16;
                    let idx = vld1q_u8(bp.masks.as_ptr().add(mbase));
                    let v = vqtbl1q_s8(tbl, idx);
                    let lo16 = vmovl_s8(vget_low_s8(v));
                    let hi16 = vmovl_s8(vget_high_s8(v));
                    p[plane][0] = vaddq_s32(p[plane][0], vmovl_s16(vget_low_s16(lo16)));
                    p[plane][1] = vaddq_s32(p[plane][1], vmovl_s16(vget_high_s16(lo16)));
                    p[plane][2] = vaddq_s32(p[plane][2], vmovl_s16(vget_low_s16(hi16)));
                    p[plane][3] = vaddq_s32(p[plane][3], vmovl_s16(vget_high_s16(hi16)));
                }
            }
            let sxq_r = sxq[reg];
            let sx_r = sx[reg];
            for q in 0..4 {
                let qd = vaddq_s32(
                    vaddq_s32(
                        vaddq_s32(p[0][q], vshlq_n_s32(p[1][q], 1)),
                        vaddq_s32(vshlq_n_s32(p[2][q], 2), vshlq_n_s32(p[3][q], 3)),
                    ),
                    vshlq_n_s32(p[4][q], 4),
                );
                let qd_f = vmulq_n_f32(vcvtq_f32_s32(qd), sxq_r);
                let a16 = vld1q_f32(bp.a.as_ptr().add((blk * regs + reg) * 16 + q * 4));
                let b16 = vld1q_f32(bp.b.as_ptr().add((blk * regs + reg) * 16 + q * 4));
                yacc[q] = vfmaq_f32(yacc[q], a16, qd_f);
                yacc[q] = vfmaq_n_f32(yacc[q], b16, sx_r);
            }
        }
        for q in 0..4 {
            vst1q_f32(chunk.as_mut_ptr().add(q * 4), yacc[q]);
        }
    });
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::math::dequantize_q5_0_row;

    fn random_q5_0(n: usize, d: usize, seed: u64) -> Vec<u8> {
        let bpr = d / 32;
        let mut s = seed;
        let mut rng = || {
            s ^= s << 13;
            s ^= s >> 7;
            s ^= s << 17;
            s
        };
        let mut w = vec![0u8; n * bpr * 22];
        for r in 0..n {
            for b in 0..bpr {
                let off = (r * bpr + b) * 22;
                w[off..off + 2].copy_from_slice(&0x2e66u16.to_le_bytes()); // d ≈ 0.1
                for k in 2..22 {
                    w[off + k] = (rng() & 0xff) as u8;
                }
            }
        }
        w
    }

    #[test]
    fn q5_0_lut_scalar_matches_dequant() {
        let (n, d) = (256usize, 512usize);
        let w = random_q5_0(n, d, 0x50_50);
        let mut s = 0x9090u64;
        let mut rng = || {
            s ^= s << 13;
            s ^= s >> 7;
            s ^= s << 17;
            s
        };
        let x: Vec<f32> = (0..d).map(|_| (rng() as i32 as f32) / (i32::MAX as f32)).collect();
        let mut y_ref = vec![0.0f32; n];
        let mut rowf = vec![0.0f32; d];
        for r in 0..n {
            dequantize_q5_0_row(&mut rowf, &w, r, d);
            y_ref[r] = rowf.iter().zip(&x).map(|(a, b)| a * b).sum();
        }
        let bp = q5_0_to_bitplanes(&w, n, d);
        let mut y_lut = vec![0.0f32; n];
        mat_vec_q5_0_lut_scalar(&mut y_lut, &x, &bp);
        let (mut num, mut den) = (0.0f64, 0.0f64);
        for r in 0..n {
            let a = y_ref[r] as f64;
            num += (a - y_lut[r] as f64).powi(2);
            den += a * a;
        }
        let rel = (num / den).sqrt();
        println!("[q5_0-lut] scalar rel-L2 vs dequant = {rel:.2e}");
        assert!(rel < 1e-4, "Q5_0 scalar LUT must match: rel={rel:.3e}");
    }

    #[cfg(target_arch = "aarch64")]
    #[test]
    fn q5_0_lut_neon_matches_and_times() {
        use crate::math::mat_vec_q5_0;
        use std::time::Instant;
        let (n, d) = (4096usize, 4096usize);
        let w = random_q5_0(n, d, 0x5eed);
        let mut s = 0xa5u64;
        let mut rng = || {
            s ^= s << 13;
            s ^= s >> 7;
            s ^= s << 17;
            s
        };
        let x: Vec<f32> = (0..d).map(|_| (rng() as i32 as f32) / (i32::MAX as f32)).collect();
        let reps = 30u128;
        let mut y_ref = vec![0.0f32; n];
        for _ in 0..3 {
            mat_vec_q5_0(&mut y_ref, &x, &w, n, d);
        }
        let t0 = Instant::now();
        for _ in 0..reps {
            mat_vec_q5_0(&mut y_ref, &x, &w, n, d);
        }
        let prod = t0.elapsed().as_nanos() / reps;
        let bp = q5_0_to_bitplanes_neon(&w, n, d);
        let mut y_lut = vec![0.0f32; n];
        for _ in 0..3 {
            mat_vec_q5_0_lut_neon(&mut y_lut, &x, &bp);
        }
        let t1 = Instant::now();
        for _ in 0..reps {
            mat_vec_q5_0_lut_neon(&mut y_lut, &x, &bp);
        }
        let lut = t1.elapsed().as_nanos() / reps;
        let (mut num, mut den) = (0.0f64, 0.0f64);
        for r in 0..n {
            let a = y_ref[r] as f64;
            num += (a - y_lut[r] as f64).powi(2);
            den += a * a;
        }
        let rel = (num / den).sqrt();
        println!(
            "[q5_0-lut NEON] {n}x{d}: prod {:.1}us  lut {:.1}us  speedup {:.2}x  rel-L2 {:.2e}",
            prod as f64 / 1e3,
            lut as f64 / 1e3,
            prod as f64 / lut as f64,
            rel
        );
        assert!(rel < 0.06, "Q5_0 neon LUT rel-L2 too high: {rel:.3e}");
    }
}
